    <text x="20" y="28" fill="#fafafa" font-size="13" font-weight="700" font-family="sans-serif">Deux significations imposées à un seul axe de score long</text>
    <defs><linearGradient id="g1fr" x1="0" y1="0" x2="1" y2="0"><stop offset="0" stop-color="#22c55e"/><stop offset="0.5" stop-color="#a3a3a3"/><stop offset="1" stop-color="#f87171"/></linearGradient></defs>
    <g font-family="sans-serif">
      <rect x="40" y="55" width="620" height="24" rx="12" fill="url(#g1fr)"/>
      <text x="45" y="105" fill="#22c55e" font-size="11" font-weight="700">10 · Fond solide</text>
